    var pencils := (b + d - 1) / d;

    CeilDivLower(a, c);
    CeilDivLower(b, d);

    if pens + pencils <= k {

      return pens, pencils;
    } else {
      assert forall x0, y0 :: !ValidAssignment(x0, y0, a, b, c, d, k) by {
